css:
.ps-wiki-toc { position: sticky; top: 1rem; background: var(--pds-surface-layer-accent); border: 1px solid var(--pds-border-subtle); border-radius: var(--pds-radius-xs); padding: var(--pds-space-2); font-family: var(--pds-font-body); font-size: 0.875rem; }
.ps-wiki-toc__heading { font-size: 0.875rem; font-weight: 700; text-transform: uppercase; letter-spacing: 0.06em; color: var(--pds-text-secondary); margin-block-end: var(--pds-space-1); }
.ps-wiki-toc__list, .ps-wiki-toc__sublist { list-style: none; padding: 0; margin: 0; }
.ps-wiki-toc__sublist { padding-inline-start: var(--pds-space-2); }
.ps-wiki-toc__link { display: block; padding-block: 0.2em; color: var(--pds-link); text-decoration: none; border-inline-start: 2px solid transparent; padding-inline-start: var(--pds-space-1); }
.ps-wiki-toc__link:hover { color: var(--pds-link-hover); }
.ps-wiki-toc__link--active, .ps-wiki-toc__link[aria-current] { border-inline-start-color: var(--pds-interactive-button-primary); color: var(--pds-text-primary); font-weight: 600; }
.ps-wiki-toc__link--sub { font-size: 0.8125rem; color: var(--pds-text-secondary); }
@media (max-width: 799px) { .ps-wiki-toc { position: static; } }
